import React from 'react'
import '../../reusable.css'
import './School.css'

function School() {
    const [allSchools, setAllSchools] = useState([])
    const [loading, setLoading] = useState(true)
    const [serverOperationError, setserverOperationError] = useState(null)
    const [serverOperationLoading, setServerOperationLoading] = useState(false)
    const [unitName, setUnitName] = useState('')
    const [chapterName, setChapterName] = useState('')
    const [unitID, setUnitID] = useState('')

    // add school func start  
    const openAddSchoolPopup = () => {
        setUnitName('')
        setserverOperationError(null)
        document.querySelector('.add-unit-popup').classList.replace('d-none', 'd-flex');
    }

    const closeAddUnitPopup = () => {
        document.querySelector('.add-unit-popup').classList.replace('d-flex', 'd-none');
    }

    const addNewUnit = () => {
        if (unitName === '') {
            setserverOperationError('Enter the unit name first!')
        } else {
            const [allUnit, setAllUnit] = useState([])
            const [loading, setLoading] = useState(true)
            const [serverOperationError, setserverOperationError] = useState(null)
            const [serverOperationLoading, setServerOperationLoading] = useState(false)
            const [unitName, setUnitName] = useState('')
            const [chapterName, setChapterName] = useState('')
            const [unitID, setUnitID] = useState('')            // addUnit(data, setserverOperationError, setServerOperationLoading, setAllUnit)
        }
    }
    // add school func end  

    return (
        <div className='school-container'>
             <div className='new-school'>
                <div className='d-flex align-items-center'>
                    <span className='add-icon'>+</span>
                    <p onClick={openAddSchoolPopup}>Add New School</p>
                </div>
            </div>
            <div className="school-cover">
                <p>test</p>
                <div>
                    <i className="fa fa-pencil" aria-hidden="true"></i>
                    <i className="fa fa-trash-o" aria-hidden="true"></i>
                </div>
            </div>
        </div>
    )
}

export default School
